// // This module selects a 32-bit value based on the address signal. When the address is low (0), it outputs 1481594924; when the address is high (1), it outputs 305419896.
module top_module(address,clock,reset_n,readdata);output [ 31: 0] readdata; 
  input address; 
  input clock; 
  input reset_n; 
  wire [ 31: 0] readdata; 
  assign readdata = address ? 1481594924 : 305419896; 
 endmodule
